  test("no_flatten_with_arg_colliding_with_arg_value_inner_scope".fail) {
    assertCompresses(
      input = """var g = ["a"];
        function problem(arg) {
            return g.indexOf(arg);
        }
        function unused(arg) {
            return problem(arg);
        }
        function a(arg) {
            return problem(arg);
        }
        function b(problem) {
            return g[problem];
        }
        function c(arg) {
            return b(a(arg));
        }
        console.log(c("a"))""".stripMargin.trim,
      expected = """var g = [ "a" ];

        function problem(arg) {
            return g.indexOf(arg);
        }

        console.log(function(problem) {
            return g[problem];
        }(function(arg) {
            return problem(arg);
        }("a")))""".stripMargin.trim,
      options = AllOff.copy(
        collapseVars = true,
        inline = InlineLevel.InlineFull,
        reduceFuncs = true,
        reduceVars = true,
        sequencesLimit = 200,
        toplevel = ToplevelConfig(funcs = true, vars = true),
        unused = true
      )
    )
  }

